	// Validate orderBy to prevent SQL injection
	// Only allow specific columns to be sorted
	allowedColumns := map[string]bool{
		"id":    true,
		"name":  true,
		"price": true,
	}
	if !allowedColumns[strings.ToLower(orderBy)] {
		return nil, errors.New("invalid sort column")
	}

	query := "SELECT id, name, price FROM products ORDER BY " + orderBy + " " + sortDir

	rows, err := db.Query(query)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		err := rows.Scan(&p.ID, &p.Name, &p.Price)
		if err != nil {
			return nil, err
		}
		products = append(products, p)
	}

	if err = rows.Err(); err != nil {
		return nil, err
	}

	return products, nil
